class Solution {
public:
    int minSwaps(vector<int>& nums) {
        int n = nums.size();
        int ones = 0;
        for (int x : nums) ones += x;
        if (ones == 0 || ones == n) return 0;

        vector<int> doubled = nums;
        doubled.insert(doubled.end(), nums.begin(), nums.end());

        int zeros = 0;
        for (int i = 0; i < ones; ++i) zeros += (doubled[i] == 0);

        int minSwaps = zeros;
        for (int i = ones; i < n + ones; ++i) {
            zeros -= (doubled[i - ones] == 0);
            zeros += (doubled[i] == 0);
            minSwaps = min(minSwaps, zeros);
        }
        return minSwaps;
    }
};
```
